// Process today's invoices (already filtered by Google Sheets)
const today = new Date().toLocaleDateString('en-CA');
const items = $input.all();

// Check if any invoices were returned from the filter
if (items.length === 0) {
  return [{
    json: {
      totalInvoices: 0,
      totalAmount: 0,
      vendors: [],
      message: `📊 **Daily Invoice Processing Summary - ${today}**\n\n❌ No invoices processed today.`
    }
  }];
}

// All items are already today's invoices (thanks to Google Sheets filter)
const todaysInvoices = items;
const totalInvoices = todaysInvoices.length;

// Calculate statistics
let totalAmount = 0;
const vendorCounts = {};
const invoiceDetails = [];

for (const invoice of todaysInvoices) {
  const amount = parseFloat(invoice.json['Total Amount']) || 0;
  totalAmount += amount;

  const vendor = invoice.json['Vendor Name'] || 'Unknown';
  vendorCounts[vendor] = (vendorCounts[vendor] || 0) + 1;

  invoiceDetails.push({
    invoiceNumber: invoice.json['Invoice Number'],
    vendor: vendor,
    amount: amount
  });
}

// Format vendor summary
const vendorSummary = Object.entries(vendorCounts)
  .map(([vendor, count]) => `• ${vendor}: ${count} invoice${count > 1 ? 's' : ''}`)
  .join('\n');

// Format invoice details
const invoiceList = invoiceDetails
  .map(inv => `• ${inv.invoiceNumber} - ${inv.vendor} - $${inv.amount.toFixed(2)}`)
  .join('\n');

// Create Teams message
const message = `📊 **Daily Invoice Processing Summary - ${today}**

✅ **Total Invoices Processed:** ${totalInvoices}
💰 **Total Amount:** $${totalAmount.toFixed(2)}

📋 **Vendor Breakdown:**
${vendorSummary}

📄 **Invoice Details:**
${invoiceList}

---
*Automated summary from n8n Invoice Processing Workflow*`;

return [{
  json: {
    totalInvoices,
    totalAmount,
    vendors: Object.keys(vendorCounts),
    message,
    invoiceDetails
  }
}];

