  const lineItems = item.json.line_items || [];

  if (lineItems.length === 0) {
    item.json.line_item_description = null;
    item.json.line_item_quantity = null;
    item.json.line_item_unit_price = null;
    item.json.line_item_amount = null;
    item.json.line_item_number = null;
    item.json.total_line_items = 0;
  }
}

const results = [];
for (const item of items) {
  const lineItems = item.json.line_items || [];

  if (lineItems.length === 0) {
    results.push(item);
  } else {
    for (let i = 0; i < lineItems.length; i++) {
      const newItem = JSON.parse(JSON.stringify(item));
      newItem.json.line_item_description = lineItems[i].description;
      newItem.json.line_item_quantity = lineItems[i].quantity;
      newItem.json.line_item_unit_price = lineItems[i].unit_price;
      newItem.json.line_item_amount = lineItems[i].amount;
      newItem.json.line_item_number = i + 1;
      newItem.json.total_line_items = lineItems.length;

      // Only show vendor name and invoice number on first line item
      if (i === 0) {
        // Keep original values for first item
        newItem.json.display_invoice_number = newItem.json.invoice_number;
        newItem.json.display_vendor_name = newItem.json.vendor_name;
      } else {
        // Empty for subsequent items
        newItem.json.display_invoice_number = "";
        newItem.json.display_vendor_name = "";
      }

      results.push(newItem);
    }
  }
}

return results;
